final class ThreadState {
    private static final ThreadLocal<RouteState> ROUTES = ThreadLocal.withInitial(RouteState::new);

    private ThreadState() {
    }

    static RouteCursor current(RevisionLedger ledger) {
        return ROUTES.get().cursorFor(ledger);
    }

    static void clear() {
        RouteState routeState = ROUTES.get();
        routeState.close();
        ROUTES.remove();
    }
